#define BLOCK_SIZE 256
#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int iteration,
    __global int *gpuWall,
    __global int *gpuSrc,
    __global int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int *prev,
    __local int *result,
    __global int *outputBuffer)
{
    const int bx = (int)get_group_id(0);
    const int tx = (int)get_local_id(0);
    const int local_block_size = (int)get_local_size(0);

    const int small_block_cols = local_block_size - iteration * HALO * 2;
    const int blockCols = cols / small_block_cols + ((cols % small_block_cols == 0) ? 0 : 1);

    if (bx >= blockCols) {
        return;
    }

    const int blkX = small_block_cols * bx - border;
    const int blkXmax = blkX + local_block_size - 1;
    const int xidx = blkX + tx;

    const int validXmin = (blkX < 0) ? (-blkX) : 0;
    const int validXmax = (blkXmax > cols - 1) ? (local_block_size - 1 - (blkXmax - cols + 1)) : (local_block_size - 1);

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    const int isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;

        if (IN_RANGE(tx, i + 1, local_block_size - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed) {
            prev[tx] = result[tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result[tx];
    }

    (void)rows;
    (void)outputBuffer;
}
